POST /premissa/cancelar { premissa_id }
Deleta cascata: storage (6 buckets) + cenas + roteiro_opcoes + videos.
Volta premissa para 'disponível' (video_id = null).

parameters.jsCode:
const item = $input.first().json;
const premissa_id = item.premissa_id || (item.body && item.body.premissa_id) || null;
if (!premissa_id) throw new Error('premissa_id obrigatório.');
return [{ json: { premissa_id } }];

// ===================================================================
// CANCELAR PREMISSA — Cascata completa
// ===================================================================
// 1. Busca todos os videos.id da premissa
// 2. Para cada video: lista e deleta arquivos nos 6 buckets de storage
// 3. Deleta cenas, roteiro_opcoes, videos
// 4. Reseta premissa para 'disponível' com video_id=null
// ===================================================================

const config = $('Configuração').first().json;
const premissa_id = $('Normalizar Input').first().json.premissa_id;
const SUPA = config.SUPABASE_URL;
const KEY = config.SUPABASE_SERVICE_KEY;

const BUCKETS = ['imagens', 'narracoes', 'efeitos', 'trilhas', 'animacoes', 'videos-finais'];

const headersJson = {
  apikey: KEY,
  Authorization: 'Bearer ' + KEY,
  'Content-Type': 'application/json'
};
const headersMinimal = { ...headersJson, Prefer: 'return=minimal' };

const log = [];

// -------------------------------------------------------------------
// 1. Buscar videos da premissa
// -------------------------------------------------------------------
const videosResp = await this.helpers.httpRequest({
  method: 'GET',
  url: SUPA + '/rest/v1/videos?premissa_id=eq.' + premissa_id + '&select=id',
  headers: headersJson,
  json: true
});

const videoIds = (videosResp || []).map(v => v.id);
log.push('videos encontrados: ' + videoIds.length);

// -------------------------------------------------------------------
// 2. Para cada video: limpar storage + deletar registros
// -------------------------------------------------------------------
for (const video_id of videoIds) {
  // 2.1 Storage: lista + delete por bucket
  for (const bucket of BUCKETS) {
    try {
      const listResp = await this.helpers.httpRequest({
        method: 'POST',
        url: SUPA + '/storage/v1/object/list/' + bucket,
        headers: headersJson,
        body: { prefix: video_id, limit: 1000, offset: 0 },
        json: true
      });

      const files = (listResp || []).map(f => video_id + '/' + f.name);
      if (files.length > 0) {
        await this.helpers.httpRequest({
          method: 'DELETE',
          url: SUPA + '/storage/v1/object/' + bucket,
          headers: headersJson,
          body: { prefixes: files },
          json: true
        });
        log.push(bucket + '/' + video_id + ': ' + files.length + ' arquivos deletados');
      }
    } catch (e) {
      log.push('ERRO storage ' + bucket + '/' + video_id + ': ' + (e.message || e));
    }
  }

  // 2.2 Deletar cenas
  try {
    await this.helpers.httpRequest({
      method: 'DELETE',
      url: SUPA + '/rest/v1/cenas?video_id=eq.' + video_id,
      headers: headersMinimal,
      json: true
    });
    log.push('cenas deletadas (video ' + video_id + ')');
  } catch (e) {
    log.push('ERRO cenas ' + video_id + ': ' + (e.message || e));
  }

  // 2.3 Deletar roteiro_opcoes
  try {
    await this.helpers.httpRequest({
      method: 'DELETE',
      url: SUPA + '/rest/v1/roteiro_opcoes?video_id=eq.' + video_id,
      headers: headersMinimal,
      json: true
    });
    log.push('roteiro_opcoes deletadas (video ' + video_id + ')');
  } catch (e) {
    log.push('ERRO roteiro_opcoes ' + video_id + ': ' + (e.message || e));
  }

  // 2.4 Deletar video
  try {
    await this.helpers.httpRequest({
      method: 'DELETE',
      url: SUPA + '/rest/v1/videos?id=eq.' + video_id,
      headers: headersMinimal,
      json: true
    });
    log.push('video ' + video_id + ' deletado');
  } catch (e) {
    log.push('ERRO delete video ' + video_id + ': ' + (e.message || e));
  }
}

// -------------------------------------------------------------------
// 3. Resetar premissa
// -------------------------------------------------------------------
try {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: SUPA + '/rest/v1/premissas?id=eq.' + premissa_id,
    headers: headersMinimal,
    body: { status: 'disponível', video_id: null },
    json: true
  });
  log.push('premissa ' + premissa_id + ' resetada para disponível');
} catch (e) {
  log.push('ERRO reset premissa: ' + (e.message || e));
}

return [{ json: { premissa_id, videos_deletados: videoIds.length, log } }];

